#include "DeadCodeElimination.hpp"

using namespace llvm;

PreservedAnalyses
DeadCodeElimination::run(Module& mod, ModuleAnalysisManager& mam)
{
  int elimTimes = 0;

  // 遍历所有函数
  for (auto& func : mod) {
    // 遍历每个函数的基本块
    for (auto& bb : func) {
      std::vector<Instruction*> instToErase;
      // 遍历每个基本块的指令
      for (auto& inst : bb) {
        // 如果指令没有副作用且结果没有被使用，则可以删除
        if (inst.isSafeToRemove() && inst.use_empty()) {
          instToErase.push_back(&inst);
          ++elimTimes;
        }
      }
      // 统一删除死代码
      for (auto& i : instToErase)
        i->eraseFromParent();
    }
  }

  mOut << "DeadCodeElimination running...\nEliminated " << elimTimes
       << " instructions\n";
  return PreservedAnalyses::all();
}

